async (params, browser) => {
  // Open Transfermarkt search
  await browser.open(`https://www.transfermarkt.com/schnellsuche/ergebnis/schnellsuche?query=${params.query}`)

  // Wait for results
  await browser.waitForSelector('.responsive-table, .box, .content', 15000)

  // Let results render
  await browser.wait(2500)

  // Extract results
  const search_results = await browser.evaluate(`const results = []; const boxes = document.querySelectorAll('.box'); let playersBox = null; for (const box of boxes) { const h2 = box.querySelector('h2'); if (h2 && /player/i.test(h2.textContent)) { playersBox = box; break; } } const container = playersBox || document; container.querySelectorAll('tbody tr.odd, tbody tr.even').forEach((el, i) => { if (i < 15) { const nameEl = el.querySelector('td.hauptlink a'); const posEl = el.querySelector('td.zentriert'); const clubEl = el.querySelector('img.tiny_wappen'); const valueEl = el.querySelector('td.rechts.hauptlink'); results.push({ name: nameEl?.getAttribute('title') || nameEl?.textContent?.trim() || '', url: nameEl?.href ? 'https://www.transfermarkt.com' + nameEl.getAttribute('href') : '', position: posEl?.textContent?.trim() || '', club: clubEl?.getAttribute('title') || '', market_value: valueEl?.textContent?.trim() || '' }); } }); return { query: '' + params.query + '', result_count: results.length, results };`)

  return search_results
}
